export const BASE_URL = 'https://mate-api.herokuapp.com';

export const NEWS_TRENDING_URL = 'https://bing-news-search1.p.rapidapi.com/news/trendingtopics?safeSearch=Off&textFormat=Raw';

// const NEWS_CATEGORY_URL = 'https://bing-news-search1.p.rapidapi.com/news?textFormat=Raw&safeSearch=Off';


export const entOpt = {
  method: 'GET',
  hostname: 'api.cognitive.microsoft.com',
  headers: {
    'content-type': 'application/json; charset=utf-8',
    'Ocp-Apim-Subscription-Key': '43f5b0b1b7msh98b68ce351846cdp1fe9bdjsn077a7897ccfa',
  },
};



export const News = 'https://www.msn.com/de-de/nachrichten/politik/polizei-stoppt-antisemitische-demo-vor-synagoge-tatverd%C3%A4chtiger-ermittelt/ar-BB1gHNWa';
export const optionsNews = {
  method: 'GET',
  headers: {
    'content-type': 'application/json; charset=utf-8',
    'x-bingapis-sdk': 'true',
    'x-rapidapi-key': '43f5b0b1b7msh98b68ce351846cdp1fe9bdjsn077a7897ccfa',
    'x-rapidapi-host': 'bing-news-search1.p.rapidapi.com',
  },
};

export const request = (url, op) => (
  fetch(url, op)
    .then(response => response.json())
    .then(res => res)
);

